package com.ijeaf.platform.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

/**
 * Configuration de sécurité Spring Security.
 *
 * <p>ÉTAT ACTUEL : permissif (base de démarrage)</p>
 * <p>TODO (OWNER: Senior) : brancher JwtAuthenticationFilter une fois le module auth implémenté.</p>
 *
 * <pre>
 *   .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
 * </pre>
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    private static final String[] PUBLIC_ENDPOINTS = {
            "/api/v1/auth/**",
            "/actuator/health",
            "/swagger-ui/**",
            "/swagger-ui.html",
            "/v3/api-docs/**"
    };

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        return http
                .csrf(AbstractHttpConfigurer::disable)
                .sessionManagement(session ->
                        session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers(PUBLIC_ENDPOINTS).permitAll()
                        // TODO (Senior) : remplacer par .anyRequest().authenticated()
                        //                 après branchement du JwtAuthenticationFilter
                        .anyRequest().permitAll())
                .build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}

package com.ijeaf.platform;

import org.junit.jupiter.api.Test;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.context.TestPropertySource;

/**
 * Test de démarrage du contexte Spring Boot.
 * Vérifie que l'application démarre sans erreur.
 * Chaque développeur doit s'assurer que ce test passe avant de pousser.
 */
@SpringBootTest
@ActiveProfiles("test")
@TestPropertySource(properties = {
        "spring.flyway.enabled=false",
        "spring.jpa.hibernate.ddl-auto=none",
        "spring.datasource.url=jdbc:h2:mem:testdb",
        "spring.datasource.driver-class-name=org.h2.Driver",
        "jwt.secret=test_secret_key_256_bits_long_for_unit_tests_only_do_not_use_in_prod",
        "jwt.access-expiration=900000",
        "jwt.refresh-expiration=604800000",
        "spring.mail.host=localhost",
        "spring.mail.port=25",
        "firebase.credentials-path=",
        "aws.access-key=test",
        "aws.secret-key=test",
        "aws.bucket-name=test",
        "aws.region=eu-west-1",
        "afriksms.api-key=test",
        "fedapay.api-key=test"
})
class IjeafApplicationTest {

    @Test
    void contextLoads() {
        // Le contexte Spring doit démarrer sans erreur
    }
}
